import os
import json
import matplotlib
matplotlib.use("Agg")
import matplotlib.pyplot as plt


TARGET_FOLDER = "image_folder\images_mnist"
HISTORY_FILE_HE = os.path.join(TARGET_FOLDER, "history_with_he.json")
HISTORY_FILE_NO_HE = os.path.join(TARGET_FOLDER, "history_without_he.json")

#Robustness specific file paths
HISTORY_FILE_BASIC = os.path.join(TARGET_FOLDER, "history_basic.json")
HISTORY_FILE_ATTACK_NO_DEF = os.path.join(TARGET_FOLDER, "history_attack_no_def.json")
HISTORY_FILE_ATTACK_DEF = os.path.join(TARGET_FOLDER, "history_attack_def.json")

def save_history(history: dict, use_he: bool = False, enable_poisoning: bool = False, use_defense: bool = False,target_folder: str = TARGET_FOLDER) -> None:
    """Save history to JSON."""
    if not os.path.exists(target_folder):
        os.makedirs(target_folder)

    #Determine the correct filename based on the current run's flags
    if use_he:
        filename = "history_with_he.json"
    elif enable_poisoning and use_defense:
        filename = "history_attack_def.json"
    elif enable_poisoning and not use_defense:
        filename = "history_attack_no_def.json"
    elif use_defense and not enable_poisoning:
        filename = "history_def_no_attack.json"  # Just in case this edge case is run
    else:
        #If no HE, no attack, and no defense, it's the baseline
        filename = "history_basic.json"

    #path = HISTORY_FILE_HE if use_he else HISTORY_FILE_NO_HE
    #path = os.path.join(target_folder, os.path.basename(path))
    path = os.path.join(target_folder, filename)
    with open(path, "w", encoding="utf-8") as f:
        json.dump(history, f, indent=2, ensure_ascii=False)
    print(f"[SERVER] History saved to {path}")


